import math

class LightweightRAG:
    def __init__(self):
        self.documents = []
        self.vectors = []

    def encode(self, text):
        t = text.lower()
        if len(t) < 2:
            return {}
        vec = {}
        for i in range(len(t) - 1):
            bg = t[i:i+2]
            vec[bg] = vec.get(bg, 0) + 1
        norm = math.sqrt(sum(v**2 for v in vec.values()))
        return {k: v / norm for k, v in vec.items()} if norm > 0 else {}

    def add_documents(self, docs):
        for doc in docs:
            self.documents.append(doc)
            self.vectors.append(self.encode(doc))
        return len(self.documents)

    def retrieve(self, query, top_k=3, use_prefix=True):
        q_text = ('query: ' + query) if use_prefix else query
        q_vec = self.encode(q_text)
        scored = []
        for doc, d_vec in zip(self.documents, self.vectors):
            dot = sum(q_vec.get(k, 0) * d_vec.get(k, 0) for k in q_vec)
            scored.append({"text": doc, "score": dot})
        scored.sort(key=lambda x: x["score"], reverse=True)
        return scored[:top_k]

    def memory_usage(self):
        return sum(len(v) for v in self.vectors)

